import * as util from "#util";
import type { LogLevel } from "./level.ts";
import type { LogRecord } from "./record.ts";

/**
 * A text formatter is a function that accepts a log record and returns
 * a string.
 *
 * @param record The log record to format.
 * @returns The formatted log record.
 */
export type TextFormatter = (record: LogRecord) => string;

/**
 * The severity level abbreviations.
 */
const levelAbbreviations: Record<LogLevel, string> = {
  "trace": "TRC",
  "debug": "DBG",
  "info": "INF",
  "warning": "WRN",
  "error": "ERR",
  "fatal": "FTL",
};

/**
 * A platform-specific inspect function.  In Deno, this is {@link Deno.inspect},
 * and in Node.js/Bun it is `util.inspect()`.  If neither is available, it
 * falls back to {@link JSON.stringify}.
 *
 * @param value The value to inspect.
 * @param options The options for inspecting the value.
 *                If `colors` is `true`, the output will be ANSI-colored.
 * @returns The string representation of the value.
 */
const platformInspect: (
  value: unknown,
  options?: { colors?: boolean },
) => string | undefined =
  // @ts-ignore: Browser detection
  // dnt-shim-ignore
  typeof document !== "undefined" ||
    // @ts-ignore: React Native detection
    // dnt-shim-ignore
    typeof navigator !== "undefined" && navigator.product === "ReactNative"
    ? (v) => JSON.stringify(v)
    // @ts-ignore: Deno global
    // dnt-shim-ignore
    : "Deno" in globalThis && "inspect" in globalThis.Deno &&
        // @ts-ignore: Deno global
        // dnt-shim-ignore
        typeof globalThis.Deno.inspect === "function"
    ? (v, opts) =>
      // @ts-ignore: Deno global
      // dnt-shim-ignore
      globalThis.Deno.inspect(v, {
        strAbbreviateSize: Infinity,
        iterableLimit: Infinity,
        ...opts,
      })
    // @ts-ignore: Node.js global
    // dnt-shim-ignore
    : util != null && "inspect" in util && typeof util.inspect === "function"
    ? (v, opts) =>
      // @ts-ignore: Node.js global
      // dnt-shim-ignore
      util.inspect(v, {
        maxArrayLength: Infinity,
        maxStringLength: Infinity,
        ...opts,
      })
    : (v) => JSON.stringify(v);

const inspect: (value: unknown, options?: { colors?: boolean }) => string = (
  value: unknown,
  options?: { colors?: boolean },
): string => String(platformInspect(value, options));

const utf8Encoder = new TextEncoder();

function renderMessageParts(
  msgParts: readonly unknown[],
  valueRenderer: (value: unknown) => string,
): string {
  const msgLen: number = msgParts.length;

  if (msgLen === 1) {
    return msgParts[0] as string;
  }

  if (msgLen <= 6) {
    let message: string = "";
    for (let i = 0; i < msgLen; i++) {
      message += (i % 2 === 0)
        ? msgParts[i] as string
        : valueRenderer(msgParts[i]);
    }
    return message;
  }

  const parts: string[] = new Array(msgLen);
  for (let i = 0; i < msgLen; i++) {
    parts[i] = (i % 2 === 0)
      ? msgParts[i] as string
      : valueRenderer(msgParts[i]);
  }
  return parts.join("");
}

/**
 * The formatted values for a log record.
 * @since 0.6.0
 */
export interface FormattedValues {
  /**
   * The formatted timestamp.
   */
  timestamp: string | null;

  /**
   * The formatted log level.
   */
  level: string;

  /**
   * The formatted category.
   */
  category: string;

  /**
   * The formatted message.
   */
  message: string;

  /**
   * The unformatted log record.
   */
  record: LogRecord;
}

/**
 * The various options for the built-in text formatters.
 * @since 0.6.0
 */
export interface TextFormatterOptions {
  /**
   * The timestamp format.  This can be one of the following:
   *
   * - `"date-time-timezone"`: The date and time with the full timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000 +00:00"`).
   * - `"date-time-tz"`: The date and time with the short timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000 +00"`).
   * - `"date-time"`: The date and time without the timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000"`).
   * - `"time-timezone"`: The time with the full timezone offset but without
   *   the date (e.g., `"22:13:20.000 +00:00"`).
   * - `"time-tz"`: The time with the short timezone offset but without the date
   *   (e.g., `"22:13:20.000 +00"`).
   * - `"time"`: The time without the date or timezone offset
   *   (e.g., `"22:13:20.000"`).
   * - `"date"`: The date without the time or timezone offset
   *   (e.g., `"2023-11-14"`).
   * - `"rfc3339"`: The date and time in RFC 3339 format
   *   (e.g., `"2023-11-14T22:13:20.000Z"`).
   * - `"none"` or `"disabled"`: No display
   *
   * Alternatively, this can be a function that accepts a timestamp and returns
   * a string.
   *
   * The default is `"date-time-timezone"`.
   */
  timestamp?:
    | "date-time-timezone"
    | "date-time-tz"
    | "date-time"
    | "time-timezone"
    | "time-tz"
    | "time"
    | "date"
    | "rfc3339"
    | "none"
    | "disabled"
    | ((ts: number) => string | null);

  /**
   * The timezone used for timestamp rendering.
   *
   * - `undefined` (default): UTC (preserves existing behavior)
   * - `null`: System local timezone
   * - IANA timezone name such as `"America/Bogota"` or `"Asia/Seoul"`
   * - Fixed UTC offset string such as `"+09:00"` or `"-05:00"`
   *
   * @since 2.1.0
   */
  timeZone?: string | null;

  /**
   * The log level format.  This can be one of the following:
   *
   * - `"ABBR"`: The log level abbreviation in uppercase (e.g., `"INF"`).
   * - `"FULL"`: The full log level name in uppercase (e.g., `"INFO"`).
   * - `"L"`: The first letter of the log level in uppercase (e.g., `"I"`).
   * - `"abbr"`: The log level abbreviation in lowercase (e.g., `"inf"`).
   * - `"full"`: The full log level name in lowercase (e.g., `"info"`).
   * - `"l"`: The first letter of the log level in lowercase (e.g., `"i"`).
   *
   * Alternatively, this can be a function that accepts a log level and returns
   * a string.
   *
   * The default is `"ABBR"`.
   */
  level?:
    | "ABBR"
    | "FULL"
    | "L"
    | "abbr"
    | "full"
    | "l"
    | ((level: LogLevel) => string);

  /**
   * The separator between category names.  For example, if the separator is
   * `"·"`, the category `["a", "b", "c"]` will be formatted as `"a·b·c"`.
   * The default separator is `"·"`.
   *
   * If this is a function, it will be called with the category array and
   * should return a string, which will be used for rendering the category.
   */
  category?: string | ((category: readonly string[]) => string);

  /**
   * The format of the embedded values.
   *
   * A function that renders a value to a string.  This function is used to
   * render the values in the log record.  The default is a cross-runtime
   * `inspect()` function that uses [`util.inspect()`] in Node.js/Bun,
   * [`Deno.inspect()`] in Deno, or falls back to {@link JSON.stringify} in
   * browsers.
   *
   * The second parameter provides access to the default cross-runtime
   * `inspect()` function, allowing you to fall back to the default behavior
   * for certain values while customizing others.  You can ignore this
   * parameter if you don't need the fallback functionality.
   *
   * [`util.inspect()`]: https://nodejs.org/api/util.html#utilinspectobject-options
   * [`Deno.inspect()`]: https://docs.deno.com/api/deno/~/Deno.inspect
   * @param value The value to render.
   * @param inspect The default cross-runtime inspect function that can be used
   *                as a fallback.  Accepts an optional `options` parameter
   *                with a `colors` boolean field.
   * @returns The string representation of the value.
   * @example
   * ```typescript
   * getTextFormatter({
   *   value(value, inspect) {
   *     // Custom formatting for numbers
   *     if (typeof value === 'number') {
   *       return value.toFixed(2);
   *     }
   *     // Fall back to default for everything else
   *     return inspect(value);
   *   }
   * })
   * ```
   */
  value?: (
    value: unknown,
    inspect: (value: unknown, options?: { colors?: boolean }) => string,
  ) => string;

  /**
   * How those formatted parts are concatenated.
   *
   * A function that formats the log record.  This function is called with the
   * formatted values and should return a string.  Note that the formatted
   * *should not* include a newline character at the end.
   *
   * By default, this is a function that formats the log record as follows:
   *
   * ```
   * 2023-11-14 22:13:20.000 +00:00 [INF] category·subcategory: Hello, world!
   * ```
   * @param values The formatted values.
   * @returns The formatted log record.
   */
  format?: (values: FormattedValues) => string;

  /**
   * Line ending style for formatted output.
   *
   * - `"lf"`: Unix-style line endings (`\n`)
   * - `"crlf"`: Windows-style line endings (`\r\n`)
   *
   * @default "lf"
   * @since 2.0.0
   */
  lineEnding?: "lf" | "crlf";
}

// Optimized helper functions for timestamp formatting
function padZero(num: number): string {
  return num < 10 ? `0${num}` : `${num}`;
}

function padThree(num: number): string {
  return num < 10 ? `00${num}` : num < 100 ? `0${num}` : `${num}`;
}

type TimestampPattern =
  | "date-time-timezone"
  | "date-time-tz"
  | "date-time"
  | "time-timezone"
  | "time-tz"
  | "time"
  | "date"
  | "rfc3339"
  | "none";

type TimeZoneConfig =
  | { kind: "utc" }
  | { kind: "local" }
  | { kind: "offset"; minutes: number }
  | { kind: "iana"; formatter: Intl.DateTimeFormat };

type DateParts = {
  year: string;
  month: string;
  day: string;
  hour: string;
  minute: string;
  second: string;
  ms: string;
  offsetMinutes: number;
};

const fixedOffsetPattern = /^([+-])(0\d|1\d|2[0-3]):([0-5]\d)$/;

function formatOffset(minutes: number, full: boolean): string {
  const sign = minutes < 0 ? "-" : "+";
  const absolute = Math.abs(minutes);
  const hour = padZero(Math.floor(absolute / 60));
  const minute = padZero(absolute % 60);
  if (!full && minute === "00") return `${sign}${hour}`;
  return `${sign}${hour}:${minute}`;
}

function readPartsFromFormatter(
  formatter: Intl.DateTimeFormat,
  ts: number,
): Omit<DateParts, "ms" | "offsetMinutes"> {
  const parts = formatter.formatToParts(new Date(ts));
  let year = "";
  let month = "";
  let day = "";
  let hour = "";
  let minute = "";
  let second = "";
  for (const part of parts) {
    if (part.type === "year") year = part.value;
    else if (part.type === "month") month = part.value;
    else if (part.type === "day") day = part.value;
    else if (part.type === "hour") hour = part.value;
    else if (part.type === "minute") minute = part.value;
    else if (part.type === "second") second = part.value;
  }
  return { year, month, day, hour, minute, second };
}

function getDateParts(ts: number, config: TimeZoneConfig): DateParts {
  const d = new Date(ts);
  const ms = padThree(d.getUTCMilliseconds());

  if (config.kind === "utc") {
    return {
      year: `${d.getUTCFullYear()}`,
      month: padZero(d.getUTCMonth() + 1),
      day: padZero(d.getUTCDate()),
      hour: padZero(d.getUTCHours()),
      minute: padZero(d.getUTCMinutes()),
      second: padZero(d.getUTCSeconds()),
      ms,
      offsetMinutes: 0,
    };
  }

  if (config.kind === "local") {
    return {
      year: `${d.getFullYear()}`,
      month: padZero(d.getMonth() + 1),
      day: padZero(d.getDate()),
      hour: padZero(d.getHours()),
      minute: padZero(d.getMinutes()),
      second: padZero(d.getSeconds()),
      ms,
      offsetMinutes: -d.getTimezoneOffset(),
    };
  }

  if (config.kind === "offset") {
    const shifted = new Date(ts + config.minutes * 60_000);
    return {
      year: `${shifted.getUTCFullYear()}`,
      month: padZero(shifted.getUTCMonth() + 1),
      day: padZero(shifted.getUTCDate()),
      hour: padZero(shifted.getUTCHours()),
      minute: padZero(shifted.getUTCMinutes()),
      second: padZero(shifted.getUTCSeconds()),
      ms,
      offsetMinutes: config.minutes,
    };
  }

  const parts = readPartsFromFormatter(config.formatter, ts);
  const asUtc = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour),
    Number(parts.minute),
    Number(parts.second),
    d.getUTCMilliseconds(),
  );
  const offsetMinutes = Math.round((asUtc - ts) / 60_000);
  return { ...parts, ms, offsetMinutes };
}

function resolveTimeZone(timeZone: string | null | undefined): TimeZoneConfig {
  if (typeof timeZone === "undefined") return { kind: "utc" };
  if (timeZone === null) return { kind: "local" };

  const offsetMatch = fixedOffsetPattern.exec(timeZone);
  if (offsetMatch != null) {
    const sign = offsetMatch[1] === "-" ? -1 : 1;
    const hours = Number(offsetMatch[2]);
    const minutes = Number(offsetMatch[3]);
    return { kind: "offset", minutes: sign * (hours * 60 + minutes) };
  }

  if (
    typeof Intl === "undefined" || typeof Intl.DateTimeFormat !== "function"
  ) {
    throw new TypeError(
      `Invalid timeZone option: ${
        JSON.stringify(timeZone)
      }. This environment does not support IANA time zones.`,
    );
  }

  try {
    return {
      kind: "iana",
      formatter: new Intl.DateTimeFormat("en-CA", {
        timeZone,
        hour12: false,
        hourCycle: "h23",
        year: "numeric",
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
      }),
    };
  } catch {
    throw new TypeError(
      `Invalid timeZone option: ${
        JSON.stringify(timeZone)
      }. Expected an IANA time zone name (e.g., "Asia/Seoul") or a fixed UTC offset string (e.g., "+09:00").`,
    );
  }
}

function createTimestampFormatter(
  pattern: TimestampPattern,
  timeZone: TimeZoneConfig,
): (ts: number) => string | null {
  if (pattern === "none") return () => null;
  if (pattern === "rfc3339" && timeZone.kind === "utc") {
    return (ts: number): string => new Date(ts).toISOString();
  }

  return (ts: number): string => {
    const parts = getDateParts(ts, timeZone);
    const date = `${parts.year}-${parts.month}-${parts.day}`;
    const time = `${parts.hour}:${parts.minute}:${parts.second}.${parts.ms}`;
    const tzLong = formatOffset(parts.offsetMinutes, true);
    const tzShort = formatOffset(parts.offsetMinutes, false);

    if (pattern === "date-time-timezone") return `${date} ${time} ${tzLong}`;
    if (pattern === "date-time-tz") return `${date} ${time} ${tzShort}`;
    if (pattern === "date-time") return `${date} ${time}`;
    if (pattern === "time-timezone") return `${time} ${tzLong}`;
    if (pattern === "time-tz") return `${time} ${tzShort}`;
    if (pattern === "time") return time;
    if (pattern === "date") return date;
    return `${date}T${time}${tzLong}`;
  };
}

// Pre-computed level renderers for common cases
const levelRenderersCache = {
  ABBR: levelAbbreviations,
  abbr: {
    trace: "trc",
    debug: "dbg",
    info: "inf",
    warning: "wrn",
    error: "err",
    fatal: "ftl",
  } as const,
  FULL: {
    trace: "TRACE",
    debug: "DEBUG",
    info: "INFO",
    warning: "WARNING",
    error: "ERROR",
    fatal: "FATAL",
  } as const,
  full: {
    trace: "trace",
    debug: "debug",
    info: "info",
    warning: "warning",
    error: "error",
    fatal: "fatal",
  } as const,
  L: {
    trace: "T",
    debug: "D",
    info: "I",
    warning: "W",
    error: "E",
    fatal: "F",
  } as const,
  l: {
    trace: "t",
    debug: "d",
    info: "i",
    warning: "w",
    error: "e",
    fatal: "f",
  } as const,
} as const;

/**
 * Helper function to get the line ending value based on the option.
 * @param lineEnding The line ending option.
 * @returns The line ending string.
 */
function getLineEndingValue(lineEnding?: "lf" | "crlf"): string {
  return lineEnding === "crlf" ? "\r\n" : "\n";
}

function jsonReplacer(_key: string, value: unknown): unknown {
  if (!(value instanceof Error)) return value;

  const serialized: Record<string, unknown> = {
    name: value.name,
    message: value.message,
  };

  if (typeof value.stack === "string") {
    serialized.stack = value.stack;
  }

  const cause = (value as { cause?: unknown }).cause;
  if (cause !== undefined) {
    serialized.cause = cause;
  }

  if (
    typeof AggregateError !== "undefined" &&
    value instanceof AggregateError
  ) {
    serialized.errors = value.errors;
  }

  for (const key of Object.keys(value)) {
    if (!(key in serialized)) {
      serialized[key] = (value as unknown as Record<string, unknown>)[key];
    }
  }

  return serialized;
}

function renderDefaultJsonLinesMessage(
  message: readonly unknown[],
): unknown {
  const messageLength = message.length;
  if (messageLength === 1) {
    return message[0];
  }
  if (messageLength === 3) {
    return (message[0] as string) + JSON.stringify(message[1]) +
      (message[2] as string);
  }

  let rendered = message[0] as string;
  for (let i = 1; i < messageLength; i++) {
    rendered += (i & 1) ? JSON.stringify(message[i]) : message[i];
  }
  return rendered;
}

function stringifyJsonLinesField(
  key: string,
  value: unknown,
): string | undefined {
  if (
    value != null &&
    (typeof value === "object" ||
      typeof value === "function" ||
      typeof value === "bigint")
  ) {
    const toJSON = (value as { toJSON?: unknown }).toJSON;
    if (typeof toJSON === "function") {
      value = toJSON.call(value, key);
    }
  }
  return JSON.stringify(jsonReplacer(key, value), jsonReplacer);
}

function formatDefaultJsonLinesRecord(
  record: LogRecord,
  lineEnding: string,
): string {
  const level = record.level === "warning"
    ? "WARN"
    : record.level.toUpperCase();
  const messageJson: string | undefined = stringifyJsonLinesField(
    "message",
    renderDefaultJsonLinesMessage(record.message),
  );
  const propertiesJson: string | undefined = stringifyJsonLinesField(
    "properties",
    record.properties,
  );

  // The default formatter always emits the same object shape, so build the
  // fixed JSON shell directly while preserving JSON.stringify() escaping,
  // toJSON field keys, Error serialization, and unsupported-value failures.
  let line = `{"@timestamp":${
    JSON.stringify(new Date(record.timestamp).toISOString())
  },"level":${JSON.stringify(level)}`;
  if (messageJson !== undefined) {
    line += `,"message":${messageJson}`;
  }
  line += `,"logger":${JSON.stringify(record.category.join("."))}`;
  if (propertiesJson !== undefined) {
    line += `,"properties":${propertiesJson}`;
  }
  return `${line}}${lineEnding}`;
}

/**
 * Get a text formatter with the specified options.  Although it's flexible
 * enough to create a custom formatter, if you want more control, you can
 * create a custom formatter that satisfies the {@link TextFormatter} type
 * instead.
 *
 * For more information on the options, see {@link TextFormatterOptions}.
 *
 * By default, the formatter formats log records as follows:
 *
 * ```
 * 2023-11-14 22:13:20.000 +00:00 [INF] category·subcategory: Hello, world!
 * ```
 * @param options The options for the text formatter.
 * @returns The text formatter.
 * @since 0.6.0
 */
export function getTextFormatter(
  options: TextFormatterOptions = {},
): TextFormatter {
  // Pre-compute timestamp formatter with optimized lookup
  const timestampRenderer = (() => {
    const tsOption = options.timestamp;
    const timeZone = resolveTimeZone(options.timeZone);
    if (tsOption == null) {
      return createTimestampFormatter("date-time-timezone", timeZone);
    } else if (tsOption === "disabled") {
      return createTimestampFormatter("none", timeZone);
    } else if (
      typeof tsOption === "string" &&
      (
        tsOption === "date-time-timezone" ||
        tsOption === "date-time-tz" ||
        tsOption === "date-time" ||
        tsOption === "time-timezone" ||
        tsOption === "time-tz" ||
        tsOption === "time" ||
        tsOption === "date" ||
        tsOption === "rfc3339" ||
        tsOption === "none"
      )
    ) {
      return createTimestampFormatter(tsOption, timeZone);
    } else {
      return tsOption as (ts: number) => string | null;
    }
  })();

  const categorySeparator = options.category ?? "·";
  const valueRenderer = options.value
    ? (v: unknown) => options.value!(v, inspect)
    : inspect;

  // Pre-compute level renderer for better performance
  const levelRenderer = (() => {
    const levelOption = options.level;
    if (levelOption == null || levelOption === "ABBR") {
      return (level: LogLevel): string => levelRenderersCache.ABBR[level];
    } else if (levelOption === "abbr") {
      return (level: LogLevel): string => levelRenderersCache.abbr[level];
    } else if (levelOption === "FULL") {
      return (level: LogLevel): string => levelRenderersCache.FULL[level];
    } else if (levelOption === "full") {
      return (level: LogLevel): string => levelRenderersCache.full[level];
    } else if (levelOption === "L") {
      return (level: LogLevel): string => levelRenderersCache.L[level];
    } else if (levelOption === "l") {
      return (level: LogLevel): string => levelRenderersCache.l[level];
    } else {
      return levelOption;
    }
  })();

  const lineEnding = getLineEndingValue(options.lineEnding);

  const formatter: (values: FormattedValues) => string = options.format ??
    (({ timestamp, level, category, message }: FormattedValues) =>
      `${timestamp ? `${timestamp} ` : ""}[${level}] ${category}: ${message}`);

  return (record: LogRecord): string => {
    const message: string = renderMessageParts(record.message, valueRenderer);

    const timestamp = timestampRenderer(record.timestamp);
    const level = levelRenderer(record.level);
    const category = typeof categorySeparator === "function"
      ? categorySeparator(record.category)
      : record.category.join(categorySeparator);

    const values: FormattedValues = {
      timestamp,
      level,
      category,
      message,
      record,
    };
    return `${formatter(values)}${lineEnding}`;
  };
}

/**
 * The default text formatter.  This formatter formats log records as follows:
 *
 * ```
 * 2023-11-14 22:13:20.000 +00:00 [INF] category·subcategory: Hello, world!
 * ```
 *
 * @param record The log record to format.
 * @returns The formatted log record.
 */
export const defaultTextFormatter: TextFormatter = getTextFormatter();

const RESET = "\x1b[0m";

/**
 * The ANSI colors.  These can be used to colorize text in the console.
 * @since 0.6.0
 */
export type AnsiColor =
  | "black"
  | "red"
  | "green"
  | "yellow"
  | "blue"
  | "magenta"
  | "cyan"
  | "white";

const ansiColors: Record<AnsiColor, string> = {
  black: "\x1b[30m",
  red: "\x1b[31m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  blue: "\x1b[34m",
  magenta: "\x1b[35m",
  cyan: "\x1b[36m",
  white: "\x1b[37m",
};

/**
 * The ANSI text styles.
 * @since 0.6.0
 */
export type AnsiStyle =
  | "bold"
  | "dim"
  | "italic"
  | "underline"
  | "strikethrough";

const ansiStyles: Record<AnsiStyle, string> = {
  bold: "\x1b[1m",
  dim: "\x1b[2m",
  italic: "\x1b[3m",
  underline: "\x1b[4m",
  strikethrough: "\x1b[9m",
};

const defaultLevelColors: Record<LogLevel, AnsiColor | null> = {
  trace: null,
  debug: "blue",
  info: "green",
  warning: "yellow",
  error: "red",
  fatal: "magenta",
};

/**
 * The various options for the ANSI color formatter.
 * @since 0.6.0
 */
export interface AnsiColorFormatterOptions extends TextFormatterOptions {
  /**
   * The timestamp format.  This can be one of the following:
   *
   * - `"date-time-timezone"`: The date and time with the full timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000 +00:00"`).
   * - `"date-time-tz"`: The date and time with the short timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000 +00"`).
   * - `"date-time"`: The date and time without the timezone offset
   *   (e.g., `"2023-11-14 22:13:20.000"`).
   * - `"time-timezone"`: The time with the full timezone offset but without
   *   the date (e.g., `"22:13:20.000 +00:00"`).
   * - `"time-tz"`: The time with the short timezone offset but without the date
   *   (e.g., `"22:13:20.000 +00"`).
   * - `"time"`: The time without the date or timezone offset
   *   (e.g., `"22:13:20.000"`).
   * - `"date"`: The date without the time or timezone offset
   *   (e.g., `"2023-11-14"`).
   * - `"rfc3339"`: The date and time in RFC 3339 format
   *   (e.g., `"2023-11-14T22:13:20.000Z"`).
   *
   * Alternatively, this can be a function that accepts a timestamp and returns
   * a string.
   *
   * The default is `"date-time-tz"`.
   */
  timestamp?:
    | "date-time-timezone"
    | "date-time-tz"
    | "date-time"
    | "time-timezone"
    | "time-tz"
    | "time"
    | "date"
    | "rfc3339"
    | "none"
    | "disabled"
    | ((ts: number) => string | null);

  /**
   * The ANSI style for the timestamp.  `"dim"` is used by default.
   */
  timestampStyle?: AnsiStyle | null;

  /**
   * The ANSI color for the timestamp.  No color is used by default.
   */
  timestampColor?: AnsiColor | null;

  /**
   * The ANSI style for the log level.  `"bold"` is used by default.
   */
  levelStyle?: AnsiStyle | null;

  /**
   * The ANSI colors for the log levels.  The default colors are as follows:
   *
   * - `"trace"`: `null` (no color)
   * - `"debug"`: `"blue"`
   * - `"info"`: `"green"`
   * - `"warning"`: `"yellow"`
   * - `"error"`: `"red"`
   * - `"fatal"`: `"magenta"`
   */
  levelColors?: Record<LogLevel, AnsiColor | null>;

  /**
   * The ANSI style for the category.  `"dim"` is used by default.
   */
  categoryStyle?: AnsiStyle | null;

  /**
   * The ANSI color for the category.  No color is used by default.
   */
  categoryColor?: AnsiColor | null;
}

/**
 * Get an ANSI color formatter with the specified options.
 *
 * ![A preview of an ANSI color formatter.](https://i.imgur.com/I8LlBUf.png)
 * @param option The options for the ANSI color formatter.
 * @returns The ANSI color formatter.
 * @since 0.6.0
 */
export function getAnsiColorFormatter(
  options: AnsiColorFormatterOptions = {},
): TextFormatter {
  const format = options.format;
  const timestampStyle = typeof options.timestampStyle === "undefined"
    ? "dim"
    : options.timestampStyle;
  const timestampColor = options.timestampColor ?? null;
  const timestampPrefix = `${
    timestampStyle == null ? "" : ansiStyles[timestampStyle]
  }${timestampColor == null ? "" : ansiColors[timestampColor]}`;
  const timestampSuffix = timestampStyle == null && timestampColor == null
    ? ""
    : RESET;
  const levelStyle = typeof options.levelStyle === "undefined"
    ? "bold"
    : options.levelStyle;
  const levelColors = options.levelColors ?? defaultLevelColors;
  const categoryStyle = typeof options.categoryStyle === "undefined"
    ? "dim"
    : options.categoryStyle;
  const categoryColor = options.categoryColor ?? null;
  const categoryPrefix = `${
    categoryStyle == null ? "" : ansiStyles[categoryStyle]
  }${categoryColor == null ? "" : ansiColors[categoryColor]}`;
  const categorySuffix = categoryStyle == null && categoryColor == null
    ? ""
    : RESET;
  return getTextFormatter({
    timestamp: "date-time-tz",
    value(value: unknown, fallbackInspect): string {
      return fallbackInspect(value, { colors: true });
    },
    ...options,
    format({ timestamp, level, category, message, record }): string {
      const levelColor = levelColors[record.level];
      timestamp = timestamp == null
        ? null
        : `${timestampPrefix}${timestamp}${timestampSuffix}`;
      level = `${levelStyle == null ? "" : ansiStyles[levelStyle]}${
        levelColor == null ? "" : ansiColors[levelColor]
      }${level}${levelStyle == null && levelColor == null ? "" : RESET}`;
      return format == null
        ? `${
          timestamp == null ? "" : `${timestamp} `
        }${level} ${categoryPrefix}${category}:${categorySuffix} ${message}`
        : format({
          timestamp,
          level,
          category: `${categoryPrefix}${category}${categorySuffix}`,
          message,
          record,
        });
    },
  });
}

/**
 * A text formatter that uses ANSI colors to format log records.
 *
 * ![A preview of ansiColorFormatter.](https://i.imgur.com/I8LlBUf.png)
 *
 * @param record The log record to format.
 * @returns The formatted log record.
 * @since 0.5.0
 */
export const ansiColorFormatter: TextFormatter = getAnsiColorFormatter();

/**
 * Options for the {@link getJsonLinesFormatter} function.
 * @since 0.11.0
 */
export interface JsonLinesFormatterOptions {
  /**
   * The separator between category names.  For example, if the separator is
   * `"."`, the category `["a", "b", "c"]` will be formatted as `"a.b.c"`.
   * If this is a function, it will be called with the category array and
   * should return a string or an array of strings, which will be used
   * for rendering the category.
   *
   * @default `"."`
   */
  readonly categorySeparator?:
    | string
    | ((category: readonly string[]) => string | readonly string[]);

  /**
   * The message format.  This can be one of the following:
   *
   * - `"template"`: The raw message template is used as the message.
   * - `"rendered"`: The message is rendered with the values.
   *
   * @default `"rendered"`
   */
  readonly message?: "template" | "rendered";

  /**
   * The properties format.  This can be one of the following:
   *
   * - `"flatten"`: The properties are flattened into the root object.
   * - `"prepend:<prefix>"`: The properties are prepended with the given prefix
   *   (e.g., `"prepend:ctx_"` will prepend `ctx_` to each property key).
   * - `"nest:<key>"`: The properties are nested under the given key
   *   (e.g., `"nest:properties"` will nest the properties under the
   *   `properties` key).
   *
   * @default `"nest:properties"`
   */
  readonly properties?: "flatten" | `prepend:${string}` | `nest:${string}`;

  /**
   * Line ending style for formatted output.
   *
   * - `"lf"`: Unix-style line endings (`\n`)
   * - `"crlf"`: Windows-style line endings (`\r\n`)
   *
   * @default "lf"
   * @since 2.0.0
   */
  readonly lineEnding?: "lf" | "crlf";
}

/**
 * Get a [JSON Lines] formatter with the specified options.  The log records
 * will be rendered as JSON objects, one per line, which is a common format
 * for log files.  This format is also known as Newline-Delimited JSON (NDJSON).
 * It looks like this:
 *
 * ```json
 * {"@timestamp":"2023-11-14T22:13:20.000Z","level":"INFO","message":"Hello, world!","logger":"my.logger","properties":{"key":"value"}}
 * ```
 *
 * [JSON Lines]: https://jsonlines.org/
 * @param options The options for the JSON Lines formatter.
 * @returns The JSON Lines formatter.
 * @since 0.11.0
 */
export function getJsonLinesFormatter(
  options: JsonLinesFormatterOptions = {},
): TextFormatter {
  const lineEnding = getLineEndingValue(options.lineEnding);

  // Most common configuration - optimize for the default case
  if (!options.categorySeparator && !options.message && !options.properties) {
    return (record: LogRecord): string =>
      formatDefaultJsonLinesRecord(record, lineEnding);
  }

  // Pre-compile configuration for non-default cases
  const isTemplateMessage = options.message === "template";
  const propertiesOption = options.properties ?? "nest:properties";

  // Pre-compile category joining strategy
  let joinCategory: (category: readonly string[]) => string | readonly string[];
  if (typeof options.categorySeparator === "function") {
    joinCategory = options.categorySeparator;
  } else {
    const separator = options.categorySeparator ?? ".";
    joinCategory = (category: readonly string[]): string =>
      category.join(separator);
  }

  // Pre-compile properties handling strategy
  let getProperties: (
    properties: Record<string, unknown>,
  ) => Record<string, unknown>;

  if (propertiesOption === "flatten") {
    getProperties = (properties) => properties;
  } else if (propertiesOption.startsWith("prepend:")) {
    const prefix = propertiesOption.substring(8);
    if (prefix === "") {
      throw new TypeError(
        `Invalid properties option: ${
          JSON.stringify(propertiesOption)
        }. It must be of the form "prepend:<prefix>" where <prefix> is a non-empty string.`,
      );
    }
    getProperties = (properties) => {
      const result: Record<string, unknown> = {};
      for (const key in properties) {
        result[`${prefix}${key}`] = properties[key];
      }
      return result;
    };
  } else if (propertiesOption.startsWith("nest:")) {
    const key = propertiesOption.substring(5);
    getProperties = (properties) => ({ [key]: properties });
  } else {
    throw new TypeError(
      `Invalid properties option: ${
        JSON.stringify(propertiesOption)
      }. It must be "flatten", "prepend:<prefix>", or "nest:<key>".`,
    );
  }

  // Pre-compile message rendering function
  let getMessage: (record: LogRecord) => string;

  if (isTemplateMessage) {
    getMessage = (record: LogRecord): string => {
      if (typeof record.rawMessage === "string") {
        return record.rawMessage;
      }
      let msg = "";
      for (let i = 0; i < record.rawMessage.length; i++) {
        if (i > 0) msg += "{}";
        msg += record.rawMessage[i];
      }
      return msg;
    };
  } else {
    getMessage = (record: LogRecord): string => {
      const msgLen = record.message.length;

      if (msgLen === 1) {
        return record.message[0] as string;
      }

      let msg = "";
      for (let i = 0; i < msgLen; i++) {
        msg += (i % 2 < 1)
          ? record.message[i]
          : JSON.stringify(record.message[i]);
      }
      return msg;
    };
  }

  return (record: LogRecord): string => {
    return JSON.stringify({
      "@timestamp": new Date(record.timestamp).toISOString(),
      level: record.level === "warning" ? "WARN" : record.level.toUpperCase(),
      message: getMessage(record),
      logger: joinCategory(record.category),
      ...getProperties(record.properties),
    }, jsonReplacer) + lineEnding;
  };
}

/**
 * The default [JSON Lines] formatter.  This formatter formats log records
 * as JSON objects, one per line, which is a common format for log files.
 * It looks like this:
 *
 * ```json
 * {"@timestamp":"2023-11-14T22:13:20.000Z","level":"INFO","message":"Hello, world!","logger":"my.logger","properties":{"key":"value"}}
 * ```
 *
 * You can customize the output by passing options to
 * {@link getJsonLinesFormatter}.  For example, you can change the category
 * separator, the message format, and how the properties are formatted.
 *
 * [JSON Lines]: https://jsonlines.org/
 * @since 0.11.0
 */
export const jsonLinesFormatter: TextFormatter = getJsonLinesFormatter();

/**
 * Options for the {@link getLogfmtFormatter} function.
 * @since 2.1.0
 */
export interface LogfmtFormatterOptions {
  /**
   * The separator between category names.  For example, if the separator is
   * `"."`, the category `["a", "b", "c"]` will be formatted as `"a.b.c"`.
   * If this is a function, it will be called with the category array and
   * should return a string, which will be used for rendering the category.
   *
   * @default `"."`
   */
  readonly categorySeparator?:
    | string
    | ((category: readonly string[]) => string);

  /**
   * The message format.  This can be one of the following:
   *
   * - `"template"`: The raw message template is used as the message.
   * - `"rendered"`: The message is rendered with the values.
   *
   * @default `"rendered"`
   */
  readonly message?: "template" | "rendered";

  /**
   * The properties format.  This can be one of the following:
   *
   * - `"flatten"`: The properties are flattened into logfmt key-value pairs.
   * - `"prepend:<prefix>"`: The properties are prepended with the given prefix
   *   (e.g., `"prepend:ctx_"` will prepend `ctx_` to each property key).
   *
   * @default `"flatten"`
   */
  readonly properties?: "flatten" | `prepend:${string}`;

  /**
   * The timezone used for timestamp rendering.
   *
   * - `undefined` (default): UTC
   * - `null`: System local timezone
   * - IANA timezone name such as `"America/Bogota"` or `"Asia/Seoul"`
   * - Fixed UTC offset string such as `"+09:00"` or `"-05:00"`
   *
   * @since 2.1.0
   */
  readonly timeZone?: string | null;

  /**
   * Line ending style for formatted output.
   *
   * - `"lf"`: Unix-style line endings (`\n`)
   * - `"crlf"`: Windows-style line endings (`\r\n`)
   *
   * @default "lf"
   * @since 2.1.0
   */
  readonly lineEnding?: "lf" | "crlf";
}

function renderStructuredMessage(record: LogRecord, template: boolean): string {
  if (template) {
    if (typeof record.rawMessage === "string") return record.rawMessage;
    return record.rawMessage.join("{}");
  }

  return renderMessageParts(record.message, stringifyLogfmtValue);
}

function filterLogfmtKey(key: string): string | null {
  if (key === "") return null;

  let needsEscape: boolean = false;
  for (const char of key) {
    const code: number = char.codePointAt(0)!;
    if (shouldEscapeLogfmtKeyChar(char, code)) {
      needsEscape = true;
      break;
    }
  }
  if (!needsEscape) return key;

  let result: string = "";
  for (const char of key) {
    const code: number = char.codePointAt(0)!;
    if (shouldEscapeLogfmtKeyChar(char, code)) {
      result += encodeLogfmtKeyChar(char);
    } else {
      result += char;
    }
  }
  return result;
}

function shouldEscapeLogfmtKeyChar(char: string, code: number): boolean {
  return code <= 0x20 || code === 0x7f || code === 0xfffd ||
    char === "=" || char === '"' || char === "%";
}

function encodeLogfmtKeyChar(char: string): string {
  let result: string = "";
  for (const byte of utf8Encoder.encode(char)) {
    result += `%${byte.toString(16).toUpperCase().padStart(2, "0")}`;
  }
  return result;
}

function stringifyLogfmtValue(value: unknown): string {
  if (typeof value === "string") return value;
  if (value === null) return "null";
  if (
    typeof value === "number" || typeof value === "boolean" ||
    typeof value === "bigint" || typeof value === "undefined" ||
    typeof value === "symbol" || typeof value === "function"
  ) {
    return String(value);
  }

  try {
    const json: string | undefined = JSON.stringify(value, jsonReplacer);
    if (typeof json === "string") return unwrapJsonStringLiteral(json);
  } catch {
    // Fall back to inspect below.
  }

  return inspect(value, { colors: false });
}

function unwrapJsonStringLiteral(json: string): string {
  if (json.startsWith('"') && json.endsWith('"')) {
    return JSON.parse(json) as string;
  }
  return json;
}

function quoteLogfmtValue(value: string, isString: boolean): string {
  let needsQuote: boolean = value === "" ||
    isString && shouldQuoteStringLiteral(value);

  for (const char of value) {
    const code: number = char.codePointAt(0)!;
    if (shouldQuoteLogfmtValueChar(char, code)) {
      needsQuote = true;
      break;
    }
  }
  if (!needsQuote) return value;

  let quoted: string = "";
  for (const char of value) {
    const code: number = char.codePointAt(0)!;
    quoted += escapeLogfmtValueChar(char, code);
  }
  return `"${quoted}"`;
}

function shouldQuoteStringLiteral(value: string): boolean {
  return value === "null" || value === "undefined" || value === "true" ||
    value === "false";
}

function shouldQuoteLogfmtValueChar(char: string, code: number): boolean {
  return code <= 0x20 || code === 0x7f || code === 0xfffd ||
    char === "=" || char === '"' || char === "\\";
}

function escapeLogfmtValueChar(char: string, code: number): string {
  switch (char) {
    case "\t":
      return "\\t";
    case "\n":
      return "\\n";
    case "\r":
      return "\\r";
    case '"':
      return '\\"';
    case "\\":
      return "\\\\";
    default:
      return code <= 0x1f || code === 0x7f
        ? `\\u${code.toString(16).padStart(4, "0")}`
        : char;
  }
}

function formatLogfmtValue(value: unknown): string {
  const stringified = stringifyLogfmtValue(value);
  return quoteLogfmtValue(stringified, typeof value === "string");
}

function pushLogfmtPair(
  pairs: string[],
  key: string,
  value: unknown,
): void {
  const filteredKey = filterLogfmtKey(key);
  if (filteredKey == null) return;
  pairs.push(`${filteredKey}=${formatLogfmtValue(value)}`);
}

/**
 * Get a [logfmt] formatter with the specified options.  The log records
 * will be rendered as space-delimited key-value pairs, one record per line.
 * It looks like this:
 *
 * ```text
 * time=2023-11-14T22:13:20.000Z level=info logger=my.logger msg="Hello, world!" key=value
 * ```
 *
 * [logfmt]: https://brandur.org/logfmt
 * @param options The options for the logfmt formatter.
 * @returns The logfmt formatter.
 * @since 2.1.0
 */
export function getLogfmtFormatter(
  options: LogfmtFormatterOptions = {},
): TextFormatter {
  const prependPrefix: string = "prepend:";
  const lineEnding: string = getLineEndingValue(options.lineEnding);
  const timestampRenderer: (ts: number) => string | null =
    createTimestampFormatter(
      "rfc3339",
      resolveTimeZone(options.timeZone),
    );
  const isTemplateMessage: boolean = options.message === "template";
  const propertiesOption: "flatten" | `prepend:${string}` =
    options.properties ?? "flatten";

  let joinCategory: (category: readonly string[]) => string;
  if (typeof options.categorySeparator === "function") {
    joinCategory = options.categorySeparator;
  } else {
    const separator = options.categorySeparator ?? ".";
    joinCategory = (category: readonly string[]): string =>
      category.join(separator);
  }

  let propertyPrefix: string = "";
  if (propertiesOption === "flatten") {
    propertyPrefix = "";
  } else if (propertiesOption.startsWith(prependPrefix)) {
    propertyPrefix = propertiesOption.substring(prependPrefix.length);
    if (propertyPrefix === "") {
      throw new TypeError(
        "Invalid properties option: " + JSON.stringify(propertiesOption) +
          ". " +
          'It must be of the form "prepend:<prefix>" where <prefix> is a ' +
          "non-empty string.",
      );
    }
  } else {
    throw new TypeError(
      `Invalid properties option: ${
        JSON.stringify(propertiesOption)
      }. It must be "flatten" or "prepend:<prefix>".`,
    );
  }

  return (record: LogRecord): string => {
    const pairs: string[] = [];
    pushLogfmtPair(pairs, "time", timestampRenderer(record.timestamp));
    pushLogfmtPair(pairs, "level", record.level);
    pushLogfmtPair(pairs, "logger", joinCategory(record.category));
    pushLogfmtPair(
      pairs,
      "msg",
      renderStructuredMessage(
        record,
        isTemplateMessage,
      ),
    );

    for (const key in record.properties) {
      if (Object.prototype.hasOwnProperty.call(record.properties, key)) {
        pushLogfmtPair(
          pairs,
          `${propertyPrefix}${key}`,
          record.properties[key],
        );
      }
    }

    return `${pairs.join(" ")}${lineEnding}`;
  };
}

/**
 * The default [logfmt] formatter.  This formatter formats log records as
 * space-delimited key-value pairs, one record per line.
 *
 * [logfmt]: https://brandur.org/logfmt
 * @since 2.1.0
 */
export const logfmtFormatter: TextFormatter = getLogfmtFormatter();

/**
 * A console formatter is a function that accepts a log record and returns
 * an array of arguments to pass to {@link console.log}.
 *
 * @param record The log record to format.
 * @returns The formatted log record, as an array of arguments for
 *          {@link console.log}.
 */
export type ConsoleFormatter = (record: LogRecord) => readonly unknown[];

/**
 * The styles for the log level in the console.
 */
const logLevelStyles: Record<LogLevel, string> = {
  "trace": "background-color: gray; color: white;",
  "debug": "background-color: gray; color: white;",
  "info": "background-color: white; color: black;",
  "warning": "background-color: orange; color: black;",
  "error": "background-color: red; color: white;",
  "fatal": "background-color: maroon; color: white;",
};

/**
 * The default console formatter.
 *
 * @param record The log record to format.
 * @returns The formatted log record, as an array of arguments for
 *          {@link console.log}.
 */
export function defaultConsoleFormatter(record: LogRecord): readonly unknown[] {
  let msg = "";
  const values: unknown[] = [];
  for (let i = 0; i < record.message.length; i++) {
    if (i % 2 === 0) msg += record.message[i];
    else {
      msg += "%o";
      values.push(record.message[i]);
    }
  }
  const date = new Date(record.timestamp);
  const time = `${date.getUTCHours().toString().padStart(2, "0")}:${
    date.getUTCMinutes().toString().padStart(2, "0")
  }:${date.getUTCSeconds().toString().padStart(2, "0")}.${
    date.getUTCMilliseconds().toString().padStart(3, "0")
  }`;
  return [
    `%c${time} %c${levelAbbreviations[record.level]}%c %c${
      record.category.join("\xb7")
    } %c${msg}`,
    "color: gray;",
    logLevelStyles[record.level],
    "background-color: default;",
    "color: gray;",
    "color: default;",
    ...values,
  ];
}
